const pgResult = $input.first().json;
const parseData = $('Parse Input').first().json;

return [{
  json: {
    documentId: pgResult.id,
    organizationId: pgResult.organization_id,
    filename: pgResult.filename,
    mimeType: pgResult.mime_type,
    fileUrl: parseData.fileUrl,
    fileToken: parseData.fileToken
  }
}];

const data = $input.first().json;
const fileUrl = data.fileUrl;
const fileToken = data.fileToken;
const mimeType = data.mimeType;
const filename = data.filename;

// Download file
const headers = {};
if (fileToken) {
  headers['Authorization'] = `Bearer ${fileToken}`;
}
const response = await fetch(fileUrl, { headers });
const buffer = Buffer.from(await response.arrayBuffer());

let text = '';

if (mimeType === 'application/pdf' || filename.endsWith('.pdf')) {
  const pdfParse = require('pdf-parse');
  const pdfData = await pdfParse(buffer);
  text = pdfData.text;
} else if (mimeType === 'application/vnd.openxmlformats-officedocument.wordprocessingml.document' || filename.endsWith('.docx')) {
  const mammoth = require('mammoth');
  const result = await mammoth.extractRawText({ buffer });
  text = result.value;
} else if (mimeType === 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' || filename.endsWith('.xlsx')) {
  const XLSX = require('xlsx');
  const workbook = XLSX.read(buffer, { type: 'buffer' });
  const sheets = workbook.SheetNames;
  text = sheets.map(name => {
    const sheet = workbook.Sheets[name];
    return XLSX.utils.sheet_to_csv(sheet);
  }).join('\n\n');
} else {
  // Plain text / markdown / etc.
  text = buffer.toString('utf-8');
}

return [{
  json: {
    ...data,
    extractedText: text
  }
}];

const data = $input.first().json;
const text = data.extractedText;
const CHUNK_SIZE = 2000;
const OVERLAP = 200;

const chunks = [];
let start = 0;

while (start < text.length) {
  const end = Math.min(start + CHUNK_SIZE, text.length);
  chunks.push(text.slice(start, end));
  start += CHUNK_SIZE - OVERLAP;
}

return [{
  json: {
    ...data,
    chunks,
    chunkCount: chunks.length
  }
}];

const crypto = require('crypto');
const data = $input.first().json;
const chunks = data.chunks;
const organizationId = data.organizationId;
const collectionName = `org_${organizationId}`;

// --- GigaChat Auth ---
const clientId = $env.GIGACHAT_CLIENT_ID;
const clientSecret = $env.GIGACHAT_CLIENT_SECRET;
const basicAuth = Buffer.from(`${clientId}:${clientSecret}`).toString('base64');

const authResponse = await fetch('https://ngw.devices.sberbank.ru:9443/api/v2/oauth', {
  method: 'POST',
  headers: {
    'Content-Type': 'application/x-www-form-urlencoded',
    'Authorization': `Basic ${basicAuth}`,
    'RqUID': crypto.randomUUID()
  },
  body: 'scope=GIGACHAT_API_PERS'
});
const authData = await authResponse.json();
const token = authData.access_token;

// --- Ensure Qdrant collection exists ---
try {
  await fetch(`http://qdrant:6333/collections/${collectionName}`, {
    method: 'PUT',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      vectors: {
        size: 1024,
        distance: 'Cosine'
      }
    })
  });
} catch (e) {
  // Collection may already exist, ignore
}

// --- Embed all chunks ---
const embResponse = await fetch('https://gigachat.devices.sberbank.ru/api/v1/embeddings', {
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    'Authorization': `Bearer ${token}`
  },
  body: JSON.stringify({
    model: 'Embeddings',
    input: chunks
  })
});
const embData = await embResponse.json();
const embeddings = embData.data.map(d => d.embedding);

// --- Upsert points to Qdrant ---
const points = embeddings.map((vector, i) => ({
  id: crypto.randomUUID(),
  vector,
  payload: {
    document_id: data.documentId,
    organization_id: organizationId,
    chunk_index: i,
    content: chunks[i]
  }
}));

await fetch(`http://qdrant:6333/collections/${collectionName}/points`, {
  method: 'PUT',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ points })
});

return [{
  json: {
    documentId: data.documentId,
    organizationId,
    filename: data.filename,
    mimeType: data.mimeType,
    chunkCount: chunks.length,
    qdrantPoints: points.map((p, i) => ({
      qdrantId: p.id,
      chunkIndex: i,
      content: chunks[i]
    }))
  }
}];

