DO $$
DECLARE
  _doc_id UUID := $1::uuid;
  _chunk_count INT := $2::int;
  _points JSONB := $3::jsonb;
  _point JSONB;
BEGIN
  FOR _point IN SELECT * FROM jsonb_array_elements(_points)
  LOOP
    INSERT INTO "DocumentChunk" (id, document_id, content, chunk_index, qdrant_id)
    VALUES (
      gen_random_uuid(),
      _doc_id,
      _point->>'content',
      (_point->>'chunkIndex')::int,
      (_point->>'qdrantId')::text
    );
  END LOOP;

  UPDATE "Document"
  SET status = 'ready',
      chunk_count = _chunk_count,
      updated_at = NOW()
  WHERE id = _doc_id;
END $$;

